Use MSTest's `[DataTestMethod]` / `[DataRow]` to make these data-driven. You can collapse all 9 methods into two:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow("hello-world", DisplayName = "Valid input")]
    [DataRow("abc",         DisplayName = "Min length (3)")]
    public void Validate_ValidInput_ReturnsTrue(string input)
    {
        var result = _validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }

    [DataTestMethod]
    [DataRow(null,             "Input cannot be empty",              DisplayName = "Null")]
    [DataRow("",               "Input cannot be empty",              DisplayName = "Empty string")]
    [DataRow("   ",            "Input cannot be empty",              DisplayName = "Whitespace only")]
    [DataRow("ab",             "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>",  "Input contains invalid characters",  DisplayName = "Special chars")]
    public void Validate_InvalidInput_ReturnsFalse(string? input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    // DataRow can't inline `new string(...)`, so boundary cases that
    // need computed values stay as a dedicated method or use DynamicData.
    [DataTestMethod]
    [DynamicData(nameof(BoundaryData), DynamicDataSourceType.Method)]
    public void Validate_BoundaryLengths(string input, bool expectedValid, string? expectedError)
    {
        var result = _validator.Validate(input);
        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    private static IEnumerable<object?[]> BoundaryData()
    {
        yield return [new string('a', 255), true,  null];
        yield return [new string('x', 256), false, "Input must not exceed 255 characters"];
    }
}
```

**Key changes:**

- **`[DataRow]`** — each new case is one attribute line, not a new method
- **`[DynamicData]`** — handles cases where inputs must be computed at runtime (like `new string(...)`)
- **`[TestInitialize]`** — removes the repeated `new InputValidator()` from every test

Adding a new validation case is now just adding one `[DataRow(...)]` line.
